import{_ as r,o as e,c as a,a3 as o}from"./chunks/framework.Daqi0Atb.js";const c=JSON.parse('{"title":"开篇词｜把一千个真实工程问题凝结成 28 个设计模式","description":"","frontmatter":{},"headers":[],"relativePath":"courses/agent-design/00-开篇词-Agent设计模式之美.md","filePath":"courses/agent-design/00-开篇词-Agent设计模式之美.md"}'),n={name:"courses/agent-design/00-开篇词-Agent设计模式之美.md"};function l(i,t,s,d,g,h){return e(),a("div",null,[...t[0]||(t[0]=[o('<h1 id="开篇词-把一千个真实工程问题凝结成-28-个设计模式" tabindex="-1">开篇词｜把一千个真实工程问题凝结成 28 个设计模式 <a class="header-anchor" href="#开篇词-把一千个真实工程问题凝结成-28-个设计模式" aria-label="Permalink to &quot;开篇词｜把一千个真实工程问题凝结成 28 个设计模式&quot;">​</a></h1><p><strong>作者</strong>：黄佳（新加坡科研局资深研发工程师，《Designing AI Agents》作者，ADPS 创始成员）</p><hr><h2 id="三代设计模式进化" tabindex="-1">三代设计模式进化 <a class="header-anchor" href="#三代设计模式进化" aria-label="Permalink to &quot;三代设计模式进化&quot;">​</a></h2><table tabindex="0"><thead><tr><th>代际</th><th>底层假设</th><th>控制流由谁决定</th></tr></thead><tbody><tr><td>GoF 23 模式</td><td>单进程 / 共享内存 / 确定性调用</td><td>写代码时固定死，运行时按写好的走</td></tr><tr><td>分布式系统模式</td><td>网络不可靠 / 节点会挂</td><td>控制流还是人写的，只是执行环境不可靠</td></tr><tr><td>Agent 设计模式</td><td>模型生成内容非确定性</td><td>一部分控制流在运行时由模型实时生成</td></tr></tbody></table><blockquote><p>GoF 的&quot;确定性&quot;本质不是&quot;系统可靠&quot;，而是<strong>控制流在编译期就被固定</strong>。 分布式的&quot;不可靠&quot;是执行环境不可靠，但控制流还是人写的。 Agent 的&quot;不稳定&quot;是<strong>连生成的内容本身都可能是非确定性的</strong>，同一 prompt 两次可能出两个不同答案。</p></blockquote><p>一句话概括：<strong>GoF 解决&quot;代码怎么组织&quot;；分布式解决&quot;服务怎么存活&quot;；Agent 解决&quot;模型怎么被约束地行动&quot;。</strong></p><hr><h2 id="核心判断" tabindex="-1">核心判断 <a class="header-anchor" href="#核心判断" aria-label="Permalink to &quot;核心判断&quot;">​</a></h2><blockquote><p><strong>Agent 的价值跟它累积的经验等比，跟它&quot;今天有多聪明&quot;反而关系不大。</strong></p></blockquote><p>一个聪明的 Agent 容易做，但三个月后它有没有记住踩过的坑？有没有学会这个仓库的规范？有没有把成功流程沉淀成 Skill？有没有因为处理过 100 个 PR 就比第 1 个 PR 时更懂这个仓库？如果没有，它只是一个每天重新入职的聪明新人。</p><p><strong>与此相关的工程目标转变：</strong></p><blockquote><p>以前写代码的工程师追求一次写对；现在做 Agent 工程的工程师追求出问题了能很快定位。</p></blockquote><p>这和&quot;价值在累积&quot;是同一枚硬币的两面：积累经验才能快速定位，定位问题才能积累经验。</p><hr><h2 id="范式转变" tabindex="-1">范式转变 <a class="header-anchor" href="#范式转变" aria-label="Permalink to &quot;范式转变&quot;">​</a></h2><p>传统软件：工程师在设计时决定控制流（输入一样，输出基本一样）</p><p>Agent 系统：控制流的一部分被交给模型在<strong>运行时</strong>决定——先看什么、查什么、调用哪个工具、要不要重试、要不要派子 Agent，这些都根据上下文动态生成。</p><p><strong>过去工程师写逻辑。现在工程师更重要的是设计决策边界。</strong></p><blockquote><p>The model spends; the harness budgets. （模型负责花，Harness 负责控制预算）</p></blockquote><hr><h2 id="双轴正交框架" tabindex="-1">双轴正交框架 <a class="header-anchor" href="#双轴正交框架" aria-label="Permalink to &quot;双轴正交框架&quot;">​</a></h2><h3 id="y-轴-·-认知功能-agent-要做什么" tabindex="-1">Y 轴 · 认知功能（Agent 要做什么） <a class="header-anchor" href="#y-轴-·-认知功能-agent-要做什么" aria-label="Permalink to &quot;Y 轴 · 认知功能（Agent 要做什么）&quot;">​</a></h3><ol><li><strong>感知</strong> — 看见世界</li><li><strong>记忆</strong> — 跨时间保存状态</li><li><strong>推理</strong> — 做判断</li><li><strong>行动</strong> — 改变外部世界</li><li><strong>反思</strong> — 检查改进自己</li><li><strong>协作</strong> — 多角色分工</li><li><strong>治理</strong> — 被信任地放进企业流程</li></ol><h3 id="x-轴-·-执行拓扑-能力如何被编排" tabindex="-1">X 轴 · 执行拓扑（能力如何被编排） <a class="header-anchor" href="#x-轴-·-执行拓扑-能力如何被编排" aria-label="Permalink to &quot;X 轴 · 执行拓扑（能力如何被编排）&quot;">​</a></h3><ol><li><strong>链式</strong> — 一步步走</li><li><strong>并行</strong> — 多路同时看</li><li><strong>路由</strong> — 从多条路里选</li><li><strong>循环</strong> — 试了再改</li><li><strong>编排</strong> — 一个角色交给另一个</li><li><strong>层级</strong> — 主 Agent 拆给子 Agent</li></ol><p>交叉形成 7×6 的工程坐标系，28 个模式在其中可以被定位、比较、组合、复盘。</p><h3 id="执行拓扑区分-易混辨析" tabindex="-1">执行拓扑区分（易混辨析） <a class="header-anchor" href="#执行拓扑区分-易混辨析" aria-label="Permalink to &quot;执行拓扑区分（易混辨析）&quot;">​</a></h3><table tabindex="0"><thead><tr><th>拓扑对</th><th>核心区别</th></tr></thead><tbody><tr><td>链式 vs 层级</td><td>链式是流水线；层级是主 Agent 拆给子 Agent，子 Agent 各管各的上下文边界，主 Agent 不一定掌握完整思考过程</td></tr><tr><td>编排 vs 层级</td><td>编排的主 Agent 全程持有完整上下文，分配任务后还要汇总；层级的子 Agent 相对独立运行</td></tr><tr><td>路由 vs 循环</td><td>路由是先判断再选路径；循环是先做，看结果，不满意就重试</td></tr></tbody></table><h3 id="三代模式-叠加而非替代" tabindex="-1">三代模式：叠加而非替代 <a class="header-anchor" href="#三代模式-叠加而非替代" aria-label="Permalink to &quot;三代模式：叠加而非替代&quot;">​</a></h3><blockquote><p>Agent 越复杂，对传统工程能力要求越高。三代模式更像是叠加关系，而非替代关系。</p><p>GoF 和分布式没有&quot;失效&quot;——它们仍然是地基，只是现在多了一层&quot;最上层&quot;的问题需要处理：Agent 运行时决策的非确定性。</p></blockquote><h3 id="工程目标的转变" tabindex="-1">工程目标的转变 <a class="header-anchor" href="#工程目标的转变" aria-label="Permalink to &quot;工程目标的转变&quot;">​</a></h3><table tabindex="0"><thead><tr><th></th><th>传统软件</th><th>Agent 系统</th></tr></thead><tbody><tr><td>目标</td><td>结构定义完 = 行为确定</td><td>结构只能提高行为稳定的<strong>概率</strong></td></tr><tr><td>控制流</td><td>编译期固定</td><td>一部分在运行时由模型生成</td></tr><tr><td>工程目标</td><td>绝对正确</td><td>在不确定性下保持系统可靠</td></tr></tbody></table><hr><h2 id="_28-个模式的本质-资源分配学" tabindex="-1">28 个模式的本质：资源分配学 <a class="header-anchor" href="#_28-个模式的本质-资源分配学" aria-label="Permalink to &quot;28 个模式的本质：资源分配学&quot;">​</a></h2><table tabindex="0"><thead><tr><th>模式类别</th><th>分配的稀缺资源</th></tr></thead><tbody><tr><td>感知模式</td><td>注意力预算</td></tr><tr><td>记忆模式</td><td>时间跨度</td></tr><tr><td>推理模式</td><td>成本、准确率和延迟</td></tr><tr><td>行动模式</td><td>副作用风险</td></tr><tr><td>反思模式</td><td>经验沉淀</td></tr><tr><td>协作模式</td><td>角色和上下文</td></tr><tr><td>治理模式</td><td>信任</td></tr></tbody></table><blockquote><p>Agent architecture is bounded resource allocation under uncertainty. Agent 架构是在不确定性下分配有限资源。</p></blockquote><hr><h2 id="课程结构-9-模块-44-篇" tabindex="-1">课程结构（9 模块 / 44 篇） <a class="header-anchor" href="#课程结构-9-模块-44-篇" aria-label="Permalink to &quot;课程结构（9 模块 / 44 篇）&quot;">​</a></h2><ol><li><strong>范式觉醒</strong> — 为什么 GoF 不够用，双轴框架是什么，逆向五步法拆 Harness</li><li><strong>感知</strong> — 上下文分诊、语义压缩、渐进发现、多模态融合</li><li><strong>记忆</strong> — 短期上下文、长期记忆、失败经验、进度追踪</li><li><strong>推理</strong> — 思维链、复杂度路由、并行探索、迭代假设验证</li><li><strong>行动</strong> — 工具调度、规划执行、提示链、护栏三明治</li><li><strong>反思</strong> — Generator-Critic、Skill Package、Experience Replay、Self-Heal Loop</li><li><strong>协作</strong> — 层级委派、扇出聚合、对抗评审、交接链</li><li><strong>治理</strong> — 审批门、爆炸半径、渐进承诺、可观测性</li><li><strong>组合</strong> — Pattern Selection Card、六步选型法、Argus Final 完整系统</li></ol><hr><h2 id="三种能力目标" tabindex="-1">三种能力目标 <a class="header-anchor" href="#三种能力目标" aria-label="Permalink to &quot;三种能力目标&quot;">​</a></h2><ol><li><strong>看穿系统</strong> — Agent 不稳定时，不只是&quot;模型不够强&quot;，知道从哪个维度定位</li><li><strong>组合模式</strong> — 真实业务是混合问题，单个模式只是零件，适配组合才叫架构</li><li><strong>设计成长机制</strong> — 失败日记、技能包、经验回放、进度追踪，让 Agent 从第 1 天聪明长成第 365 天老练</li></ol><hr><h2 id="代码仓库" tabindex="-1">代码仓库 <a class="header-anchor" href="#代码仓库" aria-label="Permalink to &quot;代码仓库&quot;">​</a></h2><ul><li><a href="https://github.com/huangjia2019/agent-design-patterns" target="_blank" rel="noreferrer">https://github.com/huangjia2019/agent-design-patterns</a> （模式案例）</li><li><a href="https://github.com/huangjia2019/designing-ai-agents" target="_blank" rel="noreferrer">https://github.com/huangjia2019/designing-ai-agents</a> （从 0 到 1 构建 Coding Agent）</li></ul><h2 id="补充-harness-vs-prompt" tabindex="-1">补充：Harness vs Prompt <a class="header-anchor" href="#补充-harness-vs-prompt" aria-label="Permalink to &quot;补充：Harness vs Prompt&quot;">​</a></h2><blockquote><p>Prompt 告诉模型&quot;该怎么做&quot;；Harness 保证&quot;即使模型没完全按预期做，系统也能把结果拉回正轨&quot;。</p></blockquote><p>举例：要求 Agent 生成带注释的 Java 代码</p><ul><li>只靠 prompt = 期待模型一次性听话</li><li>用 Harness = 把是否有注释变成<strong>可检测、可修复、可回撤、可复验</strong>的工程环节</li></ul><hr><h2 id="相关资源" tabindex="-1">相关资源 <a class="header-anchor" href="#相关资源" aria-label="Permalink to &quot;相关资源&quot;">​</a></h2><ul><li>《Designing AI Agents》英文原版（Manning，折扣码 designing-ai，$20.99）</li><li>ADPS：<a href="https://adpsagent.com" target="_blank" rel="noreferrer">https://adpsagent.com</a></li></ul>',53)])])}const b=r(n,[["render",l]]);export{c as __pageData,b as default};
